/*@ Import Coq Require Import p018_how_many_times */

int strlen(char *s)
/*@ With l n
    Require 0 <= n && n < INT_MAX &&
            Zlength(l) == n &&
            (forall (k: Z), (0 <= k && k < n) => Znth(k, l, 0) != 0) &&
            CharArray::full(s, n + 1, app(l, cons(0, nil)))
    Ensure __return == n &&
           (forall (k: Z), (0 <= k && k < n) => Znth(k, l, 0) != 0) &&
           CharArray::full(s, n + 1, app(l, cons(0, nil)))
*/
;

int p018_how_many_times(char *str, char *substring)
/*@ With l n sub m
    Require
        0 <= n && n < INT_MAX &&
        0 <= m && m < INT_MAX &&
        Zlength(l) == n &&
        Zlength(sub) == m &&
        problem_18_pre(l, sub) &&
        ascii_range(l) &&
        ascii_range(sub) &&
        (forall (k: Z), (0 <= k && k < n) => Znth(k, l, 0) != 0) &&
        (forall (k: Z), (0 <= k && k < m) => Znth(k, sub, 0) != 0) &&
        CharArray::full(str, n + 1, app(l, cons(0, nil))) *
        CharArray::full(substring, m + 1, app(sub, cons(0, nil)))
    Ensure
        (forall (k: Z), (0 <= k && k < n) => Znth(k, l, 0) != 0) &&
        (forall (k: Z), (0 <= k && k < m) => Znth(k, sub, 0) != 0) &&
        problem_18_spec(l, sub, __return) &&
        CharArray::full(str, n + 1, app(l, cons(0, nil))) *
        CharArray::full(substring, m + 1, app(sub, cons(0, nil)))
*/
{
    int out = 0;
    int i = 0;
    int j = 0;
    int ok = 0;
    int n0 = strlen(str);
    int m0 = strlen(substring);

    if (n0 == 0) {
        return 0;
    }
    if (m0 == 0) {
        return 0;
    }
    if (m0 > n0) {
        return 0;
    }

    for (i = 0; i <= n0 - m0; i++) {
        ok = 1;

        for (j = 0; j < m0; j++) {
            if (str[i + j] != substring[j]) {
                ok = 0;
            }
        }

        if (ok == 1) {
            out += 1;
        }
    }
    return out;
}

