int foo(int n)
/*@ Require 0 <= n && n < 100 && emp
    Ensure __return == n && emp
*/
{
    int cap = 12 * (n + 1) + 1;
    char *out = malloc_char_array(cap);
    int k = 1;
    int i;
    int t = 0;
    int digits = 0;
    int j = 0;
    int fill = 0;

    out[0] = 48;

    /*@ Inv Assert
        1 <= i && i <= n + 1 &&
        0 <= k && k <= cap - 1 &&
        k == Zlength(sequence_prefix(i)) &&
        k + 1 + 12 * (n - i + 1) <= cap &&
        cap == 12 * (n + 1) + 1 &&
        t >= 0 && t <= i &&
        digits >= 0 && digits <= 12 &&
        j >= 0 && j <= digits &&
        fill >= 0 && fill <= digits &&
        CharArray::full(out, k, sequence_prefix(i)) *
        CharArray::undef_seg(out, k, cap)
    */
    for (i = 1; i <= n; i++) {
        t = i;
        digits = 0;

        /*@ Inv Assert
            1 <= i && i <= n + 1 &&
            0 <= k && k <= cap - 1 &&
            k == Zlength(sequence_prefix(i)) &&
            k + 1 + 12 * (n - i + 1) <= cap &&
            cap == 12 * (n + 1) + 1 &&
            t >= 0 && t <= i &&
            digits >= 0 && digits <= 12 &&
            j >= 0 && j <= digits &&
            fill >= 0 && fill <= digits &&
            CharArray::full(out, k, sequence_prefix(i)) *
            CharArray::undef_seg(out, k, cap)
        */
        while (t > 0) {
            digits = digits + 1;
            t = t / 10;
        }

        /*@ Assert
            1 <= i && i <= n + 1 &&
            0 <= k && k <= cap - 1 &&
            k == Zlength(sequence_prefix(i)) &&
            k + 1 + 12 * (n - i + 1) <= cap &&
            cap == 12 * (n + 1) + 1 &&
            digits >= 1 && digits <= 12 &&
            j >= 0 && j <= digits &&
            fill >= 0 && fill <= digits &&
            CharArray::full(out, k, sequence_prefix(i)) *
            CharArray::undef_seg(out, k, cap)
        */

        out[k] = 32;
        k = k + 1;
    }

    return k;
}

